/**
 * Integration Tests for Notifications Module
 * NearZro Event Management Platform
 * 
 * Tests the complete notification flow:
 * 1. Notification creation (service -> database)
 * 2. Queue processing (service -> queue -> processor)
 * 3. Provider delivery (processor -> email/sms provider)
 * 
 * These tests use the full module stack with mocked external services.
 */

import { Test, TestingModule } from '@nestjs/testing';
import { NotificationsModule } from '../notifications.module';
import { NotificationsService } from '../notifications.service';
import { NotificationQueue } from '../queue/notification.queue';
import { NotificationProcessor } from '../queue/notification.processor';
import { EmailProvider } from '../providers/email.provider';
import { SmsProvider } from '../providers/sms.provider';
import { PrismaService } from '../../prisma/prisma.service';
import { NotificationChannel } from '../enums/notification-channel.enum';
import { NotificationType, NotificationPriority } from '@prisma/client';
import { getQueueToken } from '@nestjs/bull';
import { ConfigService } from '@nestjs/config';

// Mock Bull queue
const mockQueue = {
  add: jest.fn().mockResolvedValue({ id: 'test-job-id' }),
  process: jest.fn(),
};

// Mock Prisma service
const createMockPrismaService = () => ({
  notification: {
    create: jest.fn().mockImplementation((params) => 
      Promise.resolve({
        id: 1,
        userId: params.data.userId,
        type: params.data.type,
        title: params.data.title || 'Test Notification',
        message: params.data.message || 'Test message',
        priority: params.data.priority || 'NORMAL',
        read: false,
        readAt: null,
        eventId: params.data.eventId,
        createdAt: new Date(),
        updatedAt: new Date(),
        user: {
          id: params.data.userId,
          email: 'test@example.com',
          phone: '+1234567890',
        },
      })
    ),
    findUnique: jest.fn(),
    findFirst: jest.fn(),
    update: jest.fn(),
  },
  notificationPreference: {
    findMany: jest.fn().mockResolvedValue([
      { channel: NotificationChannel.EMAIL, enabled: true },
    ]),
  },
  event: {
    update: jest.fn(),
  },
  user: {
    findUnique: jest.fn().mockResolvedValue({
      id: 1,
      email: 'test@example.com',
      phone: '+1234567890',
    }),
  },
});

// Mock ConfigService
const mockConfigService = {
  get: jest.fn((key: string) => {
    const config: Record<string, any> = {
      GMAIL_USER: 'test@gmail.com',
      GMAIL_APP_PASSWORD: 'test-password',
      EMAIL_FROM: 'no-reply@nearzro.com',
      TWILIO_ACCOUNT_SID: 'test-sid',
      TWILIO_AUTH_TOKEN: 'test-token',
      TWILIO_SMS_FROM: '+1234567890',
      APP_ENV: 'test',
    };
    return config[key];
  }),
};

describe('Notifications Integration Tests', () => {
  let notificationsService: NotificationsService;
  let emailProvider: EmailProvider;
  let smsProvider: SmsProvider;
  let prisma: any;

  beforeEach(async () => {
    jest.clearAllMocks();

    const mockPrisma = createMockPrismaService();

    const module: TestingModule = await Test.createTestingModule({
      imports: [NotificationsModule],
      providers: [
        {
          provide: getQueueToken('notifications'),
          useValue: mockQueue,
        },
        {
          provide: PrismaService,
          useValue: mockPrisma,
        },
        {
          provide: ConfigService,
          useValue: mockConfigService,
        },
      ],
    })
      .overrideProvider(getQueueToken('notifications'))
      .useValue(mockQueue)
      .overrideProvider(PrismaService)
      .useValue(mockPrisma)
      .overrideProvider(ConfigService)
      .useValue(mockConfigService)
      .compile();

    notificationsService = module.get<NotificationsService>(NotificationsService);
    emailProvider = module.get<EmailProvider>(EmailProvider);
    smsProvider = module.get<SmsProvider>(SmsProvider);
    prisma = module.get<PrismaService>(PrismaService);

    // Initialize email provider
    emailProvider.onModuleInit();
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  // ============================================
  // FLOW 1: NOTIFICATION CREATION
  // ============================================
  describe('Flow 1: Notification Creation', () => {
    /**
     * Test: should create notification in database
     * Validates: NotificationsService -> Database
     */
    it('should create notification in database', async () => {
      // Arrange
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
        title: 'Booking Confirmed',
        message: 'Your booking has been confirmed',
        priority: NotificationPriority.NORMAL,
        eventId: 1,
      };

      // Act
      await notificationsService.send(dto);

      // Assert - database should be called
      expect(prisma.notification.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          userId: dto.userId,
          type: dto.type,
        }),
      });
    });

    /**
     * Test: should fetch user preferences after creation
     * Validates: Preferences resolution
     */
    it('should fetch user preferences after notification creation', async () => {
      // Arrange
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act
      await notificationsService.send(dto);

      // Assert - should query preferences
      expect(prisma.notificationPreference.findMany).toHaveBeenCalledWith({
        where: {
          userId: dto.userId,
          type: dto.type,
          enabled: true,
        },
        select: { channel: true },
      });
    });
  });

  // ============================================
  // FLOW 2: NOTIFICATION QUEUEING
  // ============================================
  describe('Flow 2: Notification Queueing', () => {
    /**
     * Test: should add job to queue for non-IN_APP channels
     * Validates: NotificationsService -> Queue
     */
    it('should add job to queue for EMAIL channel', async () => {
      // Arrange
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act
      await notificationsService.send(dto);

      // Assert - queue should receive the job
      expect(mockQueue.add).toHaveBeenCalledWith(
        'send',
        {
          notificationId: 1,
          channel: NotificationChannel.EMAIL,
        },
        expect.objectContaining({
          attempts: 3,
          backoff: expect.objectContaining({
            type: 'exponential',
          }),
        })
      );
    });

    /**
     * Test: should handle queue addition failure
     * Validates: Error handling when queue fails
     */
    it('should propagate queue errors', async () => {
      // Arrange
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };
      mockQueue.add.mockRejectedValueOnce(new Error('Redis connection failed'));

      // Act & Assert
      await expect(notificationsService.send(dto)).rejects.toThrow(
        'Redis connection failed'
      );
    });
  });

  // ============================================
  // FLOW 3: EMAIL PROVIDER DELIVERY
  // ============================================
  describe('Flow 3: Email Provider Delivery', () => {
    /**
     * Test: should send email via EmailProvider
     * Validates: Email sending works correctly
     */
    it('should send email successfully', async () => {
      // Arrange
      const to = 'test@example.com';
      const subject = 'Test Subject';
      const text = 'Test message';

      // Act
      const result = await emailProvider.send(to, subject, text);

      // Assert
      expect(result).toBe(true);
    });

    /**
     * Test: should handle email sending failure
     * Validates: Email error handling
     */
    it('should handle email sending failure', async () => {
      // Arrange - we need to mock the transporter
      const transporter = (emailProvider as any).transporter;
      transporter.sendMail.mockRejectedValueOnce(new Error('SMTP error'));

      // Act & Assert
      await expect(
        emailProvider.send('test@example.com', 'Subject', 'Message')
      ).rejects.toThrow('SMTP error');
    });
  });

  // ============================================
  // FLOW 4: SMS PROVIDER DELIVERY
  // ============================================
  describe('Flow 4: SMS Provider Delivery', () => {
    /**
     * Test: should send SMS via SmsProvider
     * Validates: SMS sending works correctly
     */
    it('should send SMS successfully', async () => {
      // Arrange
      const to = '+1234567890';
      const message = 'Test SMS';

      // Act
      await smsProvider.send(to, message);

      // Assert - SMS should be sent (mock verification)
      expect(smsProvider.send).toHaveBeenCalledWith(to, message);
    });
  });

  // ============================================
  // EDGE CASES
  // ============================================
  describe('Edge Cases', () => {
    /**
     * Test: should handle empty preferences
     * Validates: No queue job when no preferences enabled
     */
    it('should not queue when no preferences enabled', async () => {
      // Arrange
      prisma.notificationPreference.findMany.mockResolvedValueOnce([]);
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act
      await notificationsService.send(dto);

      // Assert - queue should NOT be called
      expect(mockQueue.add).not.toHaveBeenCalled();
    });

    /**
     * Test: should handle IN_APP notification (WebSocket)
     * Validates: In-app notifications don't use queue
     */
    it('should not queue IN_APP notifications', async () => {
      // Arrange
      prisma.notificationPreference.findMany.mockResolvedValueOnce([
        { channel: NotificationChannel.IN_APP, enabled: true },
      ]);
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act
      await notificationsService.send(dto);

      // Assert - queue should NOT be called for IN_APP
      expect(mockQueue.add).not.toHaveBeenCalled();
    });
  });

  // ============================================
  // ERROR HANDLING
  // ============================================
  describe('Error Handling', () => {
    /**
     * Test: should handle database creation failure
     */
    it('should throw when database creation fails', async () => {
      // Arrange
      prisma.notification.create.mockRejectedValueOnce(
        new Error('Database error')
      );
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act & Assert
      await expect(notificationsService.send(dto)).rejects.toThrow(
        'Database error'
      );
    });

    /**
     * Test: should handle preference fetch failure
     */
    it('should throw when preferences cannot be fetched', async () => {
      // Arrange
      prisma.notificationPreference.findMany.mockRejectedValueOnce(
        new Error('Preference fetch error')
      );
      const dto = {
        userId: 1,
        type: NotificationType.BOOKING_CONFIRMED,
      };

      // Act & Assert
      await expect(notificationsService.send(dto)).rejects.toThrow(
        'Preference fetch error'
      );
    });
  });
});
